 {"id":"rust_proxy-166","title":"E2E tests for Load Balancing","description":"## E2E Tests for Load Balancing

### Test Scenarios

1. **Single Strategy (Default Behavior)**
   ```rust
   #[tokio::test]
   async fn test_single_strategy_uses_active_proxy() {
       let mut harness = TestHarness::with_config(r#"
           [settings]
           load_balance_strategy = "single"
           active = "primary"

           [[proxies]]
           id = "primary"
           url = "http://localhost:MOCK1_PORT"

           [[proxies]]
           id = "secondary"
           url = "http://localhost:MOCK2_PORT"
       "#).await;

       let primary = harness.add_mock_proxy(MockBehavior::Healthy { latency_ms: 50 }).await;
       let secondary = harness.add_mock_proxy(MockBehavior::Healthy { latency_ms: 50 }).await;
       harness.start_daemon().await.unwrap();

       // Make multiple requests through proxy
       for _ in 0..10 {
           make_request_through_proxy(&harness).await;
       }

       // All requests should go to primary
       assert_eq!(primary.request_count(), 10);
       assert_eq!(secondary.request_count(), 0);
   }
   ```

2. **Round-Robin Distribution**
   ```rust
   #[tokio::test]
   async fn test_round_robin_distributes_evenly() {
       let mut harness = TestHarness::with_config(r#"
           [settings]
           load_balance_strategy = "round_robin"

           [[proxies]]
           id = "proxy-a"
           url = "http://localhost:MOCK1_PORT"

           [[proxies]]
           id = "proxy-b"
           url = "http://localhost:MOCK2_PORT"

           [[proxies]]
           id = "proxy-c"
           url = "http://localhost:MOCK3_PORT"
       "#).await;

       let mocks = harness.add_mock_proxies(3, MockBehavior::Healthy { latency_ms: 50 }).await;
       harness.start_daemon().await.unwrap();

       // Make 30 requests
       for _ in 0..30 {
           make_request_through_proxy(&harness).await;
       }

       // Each should get ~10 requests
       for mock in &mocks {
           let count = mock.request_count();
           assert!(count >= 8 && count <= 12, "Expected ~10 requests, got {}", count);
       }
   }
   ```

3. **Least-Latency Selection**
   ```rust
   #[tokio::test]
   async fn test_least_latency_prefers_fastest() {
       let mut harness = TestHarness::with_config(r#"
           [settings]
           load_balance_strategy = "least_latency"
           health_check_interval_secs = 1

           [[proxies]]
           id = "slow"
           url = "http://localhost:MOCK1_PORT"

           [[proxies]]
           id = "fast"
           url = "http://localhost:MOCK2_PORT"
       "#).await;

       let slow = harness.add_mock_proxy(MockBehavior::Healthy { latency_ms: 200 }).await;
       let fast = harness.add_mock_proxy(MockBehavior::Healthy { latency_ms: 20 }).await;
       harness.start_daemon().await.unwrap();

       // Wait for health checks to establish latency
       tokio::time::sleep(Duration::from_secs(5)).await;

       // Make requests
       for _ in 0..20 {
           make_request_through_proxy(&harness).await;
       }

       // Fast proxy should get most requests
       assert!(fast.request_count() > 15);
   }
   ```

4. **Weighted Distribution**
   ```rust
   #[tokio::test]
   async fn test_weighted_respects_weights() {
       let mut harness = TestHarness::with_config(r#"
           [settings]
           load_balance_strategy = "weighted"

           [[proxies]]
           id = "heavy"
           url = "http://localhost:MOCK1_PORT"
           weight = 80

           [[proxies]]
           id = "light"
           url = "http://localhost:MOCK2_PORT"
           weight = 20
       "#).await;

       let heavy = harness.add_mock_proxy(MockBehavior::Healthy { latency_ms: 50 }).await;
       let light = harness.add_mock_proxy(MockBehavior::Healthy { latency_ms: 50 }).await;
       harness.start_daemon().await.unwrap();

       // Make 100 requests
       for _ in 0..100 {
           make_request_through_proxy(&harness).await;
       }

       // Heavy should get ~80, light ~20 (with tolerance)
       assert!(heavy.request_count() > 60 && heavy.request_count() < 95);
       assert!(light.request_count() > 5 && light.request_count() < 40);
   }
   ```

5. **Status Command Shows Load Balancing Info**
   ```rust
   #[tokio::test]
   async fn test_status_shows_load_balancing() {
       let harness = lb_test_harness("round_robin").await;
       let output = harness.run_command(&["status"]);

       assert!(output.stdout.contains("Load Balancing: round_robin"));
   }
   ```

### Logging Requirements
- Log each request routing decision
- Log proxy selection with strategy context
- Log request counts per proxy at end of test
- On failure, dump full mock proxy request logs

