-{"id":"rust_proxy-28m","title":"Add shell detection logic","description":"## Scope

Implement logic to detect the user's current shell (bash, zsh, fish) for automatic completion installation.

## Implementation Details

### Detection Strategy

Multiple fallback methods for robustness:

```rust
#[derive(Debug, Clone, Copy, PartialEq)]
pub enum Shell {
    Bash,
    Zsh,
    Fish,
    Unknown,
}

pub fn detect_shell() -> Shell {
    // Method 1: Check $SHELL environment variable
    if let Ok(shell) = std::env::var("SHELL") {
        if shell.ends_with("/bash") || shell.ends_with("/bash.exe") {
            return Shell::Bash;
        }
        if shell.ends_with("/zsh") {
            return Shell::Zsh;
        }
        if shell.ends_with("/fish") {
            return Shell::Fish;
        }
    }

    // Method 2: Check parent process name (Linux)
    #[cfg(target_os = "linux")]
    if let Some(shell) = detect_from_parent_process() {
        return shell;
    }

    // Method 3: Check common shell rc files
    let home = dirs::home_dir();
    if let Some(home) = home {
        if home.join(".zshrc").exists() {
            return Shell::Zsh;
        }
        if home.join(".bashrc").exists() {
            return Shell::Bash;
        }
        if home.join(".config/fish/config.fish").exists() {
            return Shell::Fish;
        }
    }

    Shell::Unknown
}

#[cfg(target_os = "linux")]
fn detect_from_parent_process() -> Option<Shell> {
    let ppid = std::process::id();
    let cmdline = std::fs::read_to_string(format!("/proc/{}/comm", ppid)).ok()?;
    let name = cmdline.trim();

    match name {
        "bash" => Some(Shell::Bash),
        "zsh" => Some(Shell::Zsh),
        "fish" => Some(Shell::Fish),
        _ => None,
    }
}
```

### Shell Display Names

```rust
impl Shell {
    pub fn name(&self) -> &'static str {
        match self {
            Shell::Bash => "bash",
            Shell::Zsh => "zsh",
            Shell::Fish => "fish",
            Shell::Unknown => "unknown",
        }
    }
}
```

## Acceptance Criteria

- Detects bash, zsh, fish correctly
- Falls back through multiple detection methods
- Returns Unknown rather than guessing wrong
- Works on Linux and macOS","status":"in_progress","priority":2,"issue_type":"task","assignee":"","owner":"jeff141421@gmail.com","created_at":"2026-01-18T18:58:08.916679340Z","created_by":"Dicklesworthstone","updated_at":"2026-01-22T06:30:15.084547736Z","compaction_level":0}
