 {"id":"rust_proxy-2jn","title":"E2E tests for Network Diagnostics","description":"## E2E Tests for Network Diagnostics

### Test Scenarios

1. **Doctor Command Basic Output**
   ```rust
   #[tokio::test]
   async fn test_doctor_runs_all_checks() {
       let harness = TestHarness::new().await;

       let result = harness.run_command(&["doctor"]);

       assert!(result.success || result.exit_code == 1); // May have issues
       assert!(result.stdout.contains("Checking configuration"));
       assert!(result.stdout.contains("Checking proxy connectivity"));
       assert!(result.stdout.contains("Checking state directory"));
   }
   ```

2. **Doctor Shows Proxy Health**
   ```rust
   #[tokio::test]
   async fn test_doctor_shows_proxy_status() {
       let mut harness = TestHarness::new().await;
       let healthy = harness.add_mock_proxy(MockBehavior::Healthy { latency_ms: 50 }).await;
       let failing = harness.add_mock_proxy(MockBehavior::Failing {
           error: MockError::ConnectionRefused
       }).await;

       let result = harness.run_command(&["doctor"]);

       assert!(result.stdout.contains("OK") || result.stdout.contains("✓"));
       assert!(result.stdout.contains("FAIL") || result.stdout.contains("✗"));
   }
   ```

3. **Doctor JSON Output**
   ```rust
   #[tokio::test]
   async fn test_doctor_json_output() {
       let harness = TestHarness::new().await;

       let result = harness.run_command(&["doctor", "--json"]);

       assert!(result.success || result.exit_code == 1);
       let json: Value = serde_json::from_str(&result.stdout).unwrap();
       assert!(json["checks"].is_array());
       assert!(json["summary"].is_object());
   }
   ```

4. **Doctor Summary Shows Issue Count**
   ```rust
   #[tokio::test]
   async fn test_doctor_summary() {
       let mut harness = TestHarness::new().await;
       harness.add_mock_proxy(MockBehavior::Failing {
           error: MockError::ConnectionRefused
       }).await;

       let result = harness.run_command(&["doctor"]);

       assert!(result.stdout.contains("issue") ||
               result.stdout.contains("problem"));
   }
   ```

5. **Ping Command Basic**
   ```rust
   #[tokio::test]
   async fn test_ping_proxy() {
       let mut harness = TestHarness::new().await;
       let mock = harness.add_mock_proxy(MockBehavior::Healthy { latency_ms: 50 }).await;

       let result = harness.run_command(&["ping", &mock.id]);

       assert!(result.success);
       assert!(result.stdout.contains("PING"));
       assert!(result.stdout.contains("time="));
