   ```

6. **Ping Shows Statistics**
   ```rust
   #[tokio::test]
   async fn test_ping_shows_statistics() {
       let mut harness = TestHarness::new().await;
       let mock = harness.add_mock_proxy(MockBehavior::Healthy { latency_ms: 50 }).await;

       let result = harness.run_command(&["ping", &mock.id, "-c", "5"]);

       assert!(result.stdout.contains("min/avg/max"));
       assert!(result.stdout.contains("loss"));
   }
