7. **Ping Unknown Proxy Fails**
   ```rust
   #[tokio::test]
   async fn test_ping_unknown_proxy() {
       let harness = TestHarness::new().await;

       let result = harness.run_command(&["ping", "nonexistent-proxy"]);

       assert!(!result.success);
       assert!(result.stderr.contains("not found") ||
