Integrate degradation policy handling into the main connection handling flow, tying together all the policy implementations.

## Implementation Details

### Degradation Handler

Create a unified function that applies the configured policy:

```rust
pub async fn handle_degradation(
    config: &AppConfig,
    state: &StateStore,
    runtime: &RuntimeState,
    target: &str,
) -> Result<Option<(TcpStream, String)>> {
    // Check if we're in degraded state
    if !runtime.is_degraded().await {
        return Ok(None); // Not degraded, use normal flow
    }

    tracing::debug!(
        policy = ?config.settings.degradation_policy,
        "Applying degradation policy"
    );

    match config.settings.degradation_policy {
        DegradationPolicy::FailClosed => {
            apply_fail_closed_policy().await?;
            unreachable!() // fail_closed always returns Err
        }

        DegradationPolicy::TryAll => {
            let (stream, proxy_id) = apply_try_all_policy(config, target).await?;
            Ok(Some((stream, proxy_id)))
        }

        DegradationPolicy::UseLast => {
            let (stream, proxy_id) = apply_use_last_policy(config, state, target).await?;
            Ok(Some((stream, proxy_id)))
        }

        DegradationPolicy::Direct => {
            if !config.settings.allow_direct_fallback {
                // Should be caught by validation, but double-check
                anyhow::bail!("Direct fallback not allowed");
            }
            let stream = TcpStream::connect(target).await?;
            tracing::warn!(target = %target, "Connected directly (no proxy)");
            Ok(Some((stream, "direct".to_string())))
        }
    }
}
```

### Connection Handler Integration

```rust
async fn handle_connection(
    stream: TcpStream,
    config: Arc<AppConfig>,
    state: Arc<StateStore>,
    runtime: Arc<RuntimeState>,
    load_balancer: Arc<LoadBalancer>,
) {
    let target = parse_connect_request(&stream).await?;

    // Try normal proxy selection first
    let proxy_result = load_balancer.select_proxy(
        config.settings.load_balance_strategy,
        &config.proxies,
        &state,
    ).await;

    let (proxy_stream, proxy_id) = match proxy_result {
        Some(proxy_id) => {
            // Normal path - healthy proxy available
            let proxy = config.proxies.iter().find(|p| p.id == proxy_id).unwrap();
            let stream = connect_through_proxy(proxy, &target).await?;
            (stream, proxy_id)
        }
        None => {
            // No healthy proxy - apply degradation policy
            match handle_degradation(&config, &state, &runtime, &target).await? {
                Some((stream, id)) => (stream, id),
                None => {
                    // Degradation not active yet (within delay)
                    // Fall back to fail_closed behavior
                    apply_fail_closed_policy().await?;
                    return;
                }
            }
        }
    };

    tracing::debug!(proxy = %proxy_id, target = %target, "Connection established");

    // ... proceed with bidirectional copy
}
